#include <stdbool.h>

// Helper JSON parser for array of strings
typedef struct {
    const char* s;
    int pos;
    int len;
} Tok;

static void skipWS(Tok* t) {
    while (t->pos < t->len && (t->s[t->pos] == ' ' || t->s[t->pos] == '\t' || t->s[t->pos] == '\n' || t->s[t->pos] == '\r' || t->s[t->pos] == ',')) {
        t->pos++;
    }
}

static char* parseString(Tok* t) {
    skipWS(t);
    if (t->pos >= t->len || t->s[t->pos] != '"') return NULL;
    t->pos++; // skip opening quote
    int start = t->pos;
    while (t->pos < t->len && t->s[t->pos] != '"') t->pos++;
    if (t->pos >= t->len) return NULL;
    int length = t->pos - start;
    char* str = (char*)malloc(length + 1);
    memcpy(str, t->s + start, length);
    str[length] = '\0';
    t->pos++; // skip closing quote
    return str;
}

static int parseStringArray(Tok* t, char*** outArr) {
    skipWS(t);
    if (t->pos >= t->len || t->s[t->pos] != '[') return 0;
    t->pos++; // skip '['

    // First pass: count strings
    int count = 0;
    int savePos = t->pos;
    while (t->pos < t->len) {
        skipWS(t);
        if (t->s[t->pos] == ']') break;
        if (t->s[t->pos] == '"') {
            count++;
            // parse and discard
            t->pos++;
            while (t->pos < t->len && t->s[t->pos] != '"') t->pos++;
            if (t->pos < t->len) t->pos++;
        } else {
            // skip until comma or ]
            while (t->pos < t->len && t->s[t->pos] != ',' && t->s[t->pos] != ']') t->pos++;
        }
        skipWS(t);
        if (t->pos < t->len && t->s[t->pos] == ',') t->pos++;
    }
    if (t->pos < t->len && t->s[t->pos] == ']') t->pos++;

    // Allocate array
    *outArr = (char**)malloc(count * sizeof(char*));

    // Second pass: actually parse
    t->pos = savePos;
    for (int i = 0; i < count; i++) {
        (*outArr)[i] = parseString(t);
        skipWS(t);
        if (t->pos < t->len && t->s[t->pos] == ',') t->pos++;
    }
    return count;
}

